patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 58605a5da3de8..9099aeae1b153 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -42,6 +42,7 @@
 #include "llvm/Support/Casting.h"
 #include "llvm/Support/ErrorHandling.h"
 #include "llvm/Support/KnownBits.h"
+#include "llvm/Support/MathExtras.h"
 #include "llvm/Transforms/InstCombine/InstCombiner.h"
 #include <cassert>
 #include <optional>
@@ -1513,11 +1514,10 @@ static Instruction *foldSelectCtlzToCttz(ICmpInst *ICI, Value *TrueVal,
     std::swap(TrueVal, FalseVal);

   Value *Ctlz;
-  if (!match(FalseVal,
-             m_Xor(m_Value(Ctlz), m_SpecificInt(BitWidth - 1))))
+  if (!match(FalseVal, m_Xor(m_Value(Ctlz), m_SpecificInt(BitWidth - 1))))
     return nullptr;

-  if (!match(Ctlz, m_Ctlz(m_Value(), m_Value())))
+  if (!isPowerOf2_64(BitWidth) || !match(Ctlz, m_Ctlz(m_Value(), m_Value())))
     return nullptr;

   if (TrueVal != Ctlz && !match(TrueVal, m_SpecificInt(BitWidth)))

tests.test_body:
declare i33 @select_clz_to_ctz_sub_non_pot(i33)

define i33 @select_clz_to_ctz_sub_non_pot_two() {
  %r = call i33 @select_clz_to_ctz_sub_non_pot(i33 2)
  ret i33 %r
}

declare i33 @select_clz_to_ctz_xor_non_pot(i33)

define i33 @select_clz_to_ctz_xor_non_pot_two() {
  %r = call i33 @select_clz_to_ctz_xor_non_pot(i33 2)
  ret i33 %r
}
